from haystack import Pipeline
from haystack.components.builders import PromptBuilder
from haystack.utils import ComponentDevice

import json
from typing import Dict, Any, List
from collections import defaultdict

class OutputSchemaValidator:
    def __init__(self):
        self.schemas = defaultdict(list)

    def validate_pipeline_outputs(self, pipeline: Pipeline, test_inputs: List[Dict]):
        inconsistencies = []

        for i, inputs in enumerate(test_inputs):
            try:
                result = pipeline.run(**inputs)
                output_schema = self._extract_schema(result)
                self.schemas[inputs['query'][:50]].append(output_schema)

                # Check against previous runs
                prev_schemas = self.schemas[inputs['query'][:50]][:-1]
                if prev_schemas and not self._schemas_match(output_schema, prev_schemas[0]):
                    inconsistencies.append({
                        'input': inputs,
                        'schema': output_schema,
                        'expected': prev_schemas[0]
                    })
            except Exception as e:
                inconsistencies.append({'input': inputs, 'error': str(e)})

        return {
            'inconsistency_rate': len(inconsistencies) / len(test_inputs),
            'examples': inconsistencies[:5]
        }

    def _extract_schema(self, result: Dict[str, Any]) -> Dict:
        schema = {}
        for key, value in result.items():
            if isinstance(value, dict):
                schema[key] = {'type': 'dict', 'keys': list(value.keys())}
            elif isinstance(value, list):
                schema[key] = {'type': 'list', 'sample': value[0] if value else None}
            else:
                schema[key] = {'type': type(value).__name__}
        return schema

    def _schemas_match(self, schema1: Dict, schema2: Dict) -> bool:
        return json.dumps(schema1, sort_keys=True) == json.dumps(schema2, sort_keys=True)

from haystack import Pipeline
from typing import Dict, Any, List

from dataclasses import dataclass
from typing import Optional

@dataclass
class TypeDriftAlert:
    component: str
    expected_type: str
    actual_type: str
    run_id: int
    sample_output: Any

class ComponentTypeMonitor:
    def __init__(self):
        self.type_registry: Dict[str, Dict] = {}

    def monitor_pipeline(self, pipeline: Pipeline, inputs: List[Dict]):
        alerts = []

        for i, input_data in enumerate(inputs):
            # Enable debug tracing
            pipeline.trace(f"run-{i}")
            result = pipeline.run(**input_data)

            # Check each component output
            for component_name, output in result.items():
                self._check_type_consistency(component_name, output, i, alerts)

        return {
            'total_alerts': len(alerts),
            'drift_rate': len(set(a.component for a in alerts)) / len(result),
            'alerts': alerts
        }

    def _check_type_consistency(self, component_name: str, output: Any, run_id: int, alerts: List):
        if component_name not in self.type_registry:
            self.type_registry[component_name] = {'type': type(output).__name__, 'count': 1}
        else:
            expected_type = self.type_registry[component_name]['type']
            actual_type = type(output).__name__

            if expected_type != actual_type:
                alerts.append(TypeDriftAlert(
                    component=component_name,
                    expected_type=expected_type,
                    actual_type=actual_type,
                    run_id=run_id,
                    sample_output=output
                ))

