from haystack import component

@component
class OutputNormalizer:
    @component.output_types(reports=dict, normalized=dict)
    def run(self, raw_output: dict) -> dict:
        normalized = {
            'answer': raw_output.get('answer', ''),
            'context': [doc.get('content', '') for doc in raw_output.get('documents', [])],
            'sources': [{'title': d.get('meta', {}).get('title', ''), 'url': d.get('meta', {}).get('url', '')} 
                       for d in raw_output.get('documents', [])],
            'confidence': raw_output.get('score', 0.0),
            'is_consistent': True
        }

        reports = {'input_keys': list(raw_output.keys()), 'normalization_applied': True}
        return {'reports': reports, 'normalized': normalized}

